<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">Seçim Destekleyici Yanlılığın Kendini Güçlendiren Döngüsü</text>
  <text x="20" y="46" fill="#71717a" font-size="11" font-family="sans-serif">Pozisyon aynı kalır — yalnızca gerekçe değişmeye devam eder</text>
  <defs><marker id="arrtr" viewBox="0 0 10 10" refX="8" refY="5" markerWidth="6" markerHeight="6" orient="auto-start-reverse"><path d="M0,0 L10,5 L0,10 z" fill="#a78bfa"/></marker></defs>
  <rect x="30" y="70" width="190" height="70" rx="8" fill="#1c1c20" stroke="#3f3f46"/>
  <text x="125" y="100" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif" text-anchor="middle">① Alım</text>
  <text x="125" y="122" fill="#a1a1aa" font-size="12" font-family="sans-serif" text-anchor="middle">İlk tez: ödeme aracı</text>
  <rect x="255" y="70" width="190" height="70" rx="8" fill="#1c1c20" stroke="#3f3f46"/>
  <text x="350" y="100" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif" text-anchor="middle">② Tez sarsılır</text>
  <text x="350" y="122" fill="#a1a1aa" font-size="12" font-family="sans-serif" text-anchor="middle">Benimseme durur, fiyat düşer</text>
  <rect x="480" y="70" width="190" height="70" rx="8" fill="#7c3aed" fill-opacity="0.85" stroke="#a78bfa"/>
  <text x="575" y="100" fill="#fdf4ff" font-size="14" font-weight="700" font-family="sans-serif" text-anchor="middle">③ Hafıza yeniden yazılır</text>
